class SmallestInfiniteSet {
    constructor() {
        this.counter = 1;
        this.added = new Set();
    }
    popSmallest() {
        if (this.added.size > 0) {
            let m = Infinity;
            for (const v of this.added) if (v < m) m = v;
            this.added.delete(m);
            return m;
        }
        return this.counter++;
    }
    addBack(num) {
        if (num < this.counter) this.added.add(num);
    }
}
